1761					reg_sh <= cpuregs_rs2;
1762					reg_op2 <= cpuregs_rs2;
1763					dbg_rs2val <= cpuregs_rs2;
1764					dbg_rs2val_valid <= 1;
1765	
1766					(* parallel_case *)
1767					case (1'b1)
1768						WITH_PCPI && instr_trap: begin
1769							pcpi_valid <= 1;
1770							if (pcpi_int_ready) begin
1771								mem_do_rinst <= 1;
1772								pcpi_valid <= 0;
1773								reg_out <= pcpi_int_rd;
1774								latched_store <= pcpi_int_wr;
1775								cpu_state <= cpu_state_fetch;
1776							end else
1777							if (CATCH_ILLINSN && (pcpi_timeout || instr_ecall_ebreak)) begin
1778								pcpi_valid <= 0;
1779								`debug($display("EBREAK OR UNSUPPORTED INSN AT 0x%08x", reg_pc);)
1780								if (ENABLE_IRQ && !irq_mask[irq_ebreak] && !irq_active) begin
1781									next_irq_pending[irq_ebreak] = 1;
1782									cpu_state <= cpu_state_fetch;
1783								end else
1784									cpu_state <= cpu_state_trap;
1785							end
1786						end
1787						is_sb_sh_sw: begin
1788							cpu_state <= cpu_state_stmem;
1789							mem_do_rinst <= 1;
1790						end
1791						is_sll_srl_sra && !BARREL_SHIFTER: begin
1792							cpu_state <= cpu_state_shift;
1793						end
1794						default: begin
1795							if (TWO_CYCLE_ALU || (TWO_CYCLE_COMPARE && is_beq_bne_blt_bge_bltu_bgeu)) begin
1796								alu_wait_2 <= TWO_CYCLE_ALU && (TWO_CYCLE_COMPARE && is_beq_bne_blt_bge_bltu_bgeu);
1797								alu_wait <= 1;
1798							end else
1799								mem_do_rinst <= mem_do_prefetch;
1800							cpu_state <= cpu_state_exec;
1801						end
1802					endcase
1803				end
1804	
1805				cpu_state_exec: begin
1806					reg_out <= reg_pc + decoded_imm;
1807					if ((TWO_CYCLE_ALU || TWO_CYCLE_COMPARE) && (alu_wait || alu_wait_2)) begin
1808						mem_do_rinst <= mem_do_prefetch && !alu_wait_2;
1809						alu_wait <= alu_wait_2;
1810					end else
1811					if (is_beq_bne_blt_bge_bltu_bgeu) begin
1812						latched_rd <= 0;
1813						latched_store <= TWO_CYCLE_COMPARE ? alu_out_0_q : alu_out_0;
1814						latched_branch <= TWO_CYCLE_COMPARE ? alu_out_0_q : alu_out_0;
1815						if (mem_done)
1816							cpu_state <= cpu_state_fetch;
1817						if (TWO_CYCLE_COMPARE ? alu_out_0_q : alu_out_0) begin
1818							decoder_trigger <= 0;
1819							set_mem_do_rinst = 1;
1820						end
1821					end else begin
1822						latched_branch <= instr_jalr;
1823						latched_store <= 1;
1824						latched_stalu <= 1;
1825						cpu_state <= cpu_state_fetch;
1826					end
1827				end
1828	
1829				cpu_state_shift: begin
1830					latched_store <= 1;
1831					if (reg_sh == 0) begin
1832						reg_out <= reg_op1;
1833						mem_do_rinst <= mem_do_prefetch;
1834						cpu_state <= cpu_state_fetch;
1835					end else if (TWO_STAGE_SHIFT && reg_sh >= 4) begin
1836						(* parallel_case, full_case *)
1837						case (1'b1)
1838							instr_slli || instr_sll: reg_op1 <= reg_op1 << 4;
1839							instr_srli || instr_srl: reg_op1 <= reg_op1 >> 4;
1840							instr_srai || instr_sra: reg_op1 <= $signed(reg_op1) >>> 4;
1841						endcase
1842						reg_sh <= reg_sh - 4;
1843					end else begin
1844						(* parallel_case, full_case *)
1845						case (1'b1)
1846							instr_slli || instr_sll: reg_op1 <= reg_op1 << 1;
1847							instr_srli || instr_srl: reg_op1 <= reg_op1 >> 1;
1848							instr_srai || instr_sra: reg_op1 <= $signed(reg_op1) >>> 1;
1849						endcase
1850						reg_sh <= reg_sh - 1;
1851					end
1852				end
1853	
1854				cpu_state_stmem: begin
1855					if (ENABLE_TRACE)
1856						reg_out <= reg_op2;
1857					if (!mem_do_prefetch || mem_done) begin
1858						if (!mem_do_wdata) begin
1859							(* parallel_case, full_case *)
1860							case (1'b1)
1861								instr_sb: mem_wordsize <= 2;
1862								instr_sh: mem_wordsize <= 1;
1863								instr_sw: mem_wordsize <= 0;
1864							endcase
1865							if (ENABLE_TRACE) begin
1866								trace_valid <= 1;
1867								trace_data <= (irq_active ? TRACE_IRQ : 0) | TRACE_ADDR | ((reg_op1 + decoded_imm) & 32'hffffffff);
1868							end
1869							reg_op1 <= reg_op1 + decoded_imm;
1870							set_mem_do_wdata = 1;
1871						end
1872						if (!mem_do_prefetch && mem_done) begin
1873							cpu_state <= cpu_state_fetch;
1874							decoder_trigger <= 1;
1875							decoder_pseudo_trigger <= 1;
1876						end
1877					end
1878				end
1879	
1880				cpu_state_ldmem: begin
1881					latched_store <= 1;
1882					if (!mem_do_prefetch || mem_done) begin
1883						if (!mem_do_rdata) begin
1884							(* parallel_case, full_case *)
1885							case (1'b1)
1886								instr_lb || instr_lbu: mem_wordsize <= 2;
1887								instr_lh || instr_lhu: mem_wordsize <= 1;
1888								instr_lw: mem_wordsize <= 0;
1889							endcase
1890							latched_is_lu <= is_lbu_lhu_lw;
1891							latched_is_lh <= instr_lh;
1892							latched_is_lb <= instr_lb;
1893							if (ENABLE_TRACE) begin
1894								trace_valid <= 1;
1895								trace_data <= (irq_active ? TRACE_IRQ : 0) | TRACE_ADDR | ((reg_op1 + decoded_imm) & 32'hffffffff);
1896							end
1897							reg_op1 <= reg_op1 + decoded_imm;
1898							set_mem_do_rdata = 1;
1899						end
1900						if (!mem_do_prefetch && mem_done) begin
1901							(* parallel_case, full_case *)
1902							case (1'b1)
1903								latched_is_lu: reg_out <= mem_rdata_word;
1904								latched_is_lh: reg_out <= $signed(mem_rdata_word[15:0]);
1905								latched_is_lb: reg_out <= $signed(mem_rdata_word[7:0]);
1906							endcase
1907							decoder_trigger <= 1;
1908							decoder_pseudo_trigger <= 1;
1909							cpu_state <= cpu_state_fetch;
1910						end
1911					end
1912				end
1913			endcase
1914	
1915			if (ENABLE_IRQ) begin
1916				next_irq_pending = next_irq_pending | irq;
1917				if(ENABLE_IRQ_TIMER && timer)
1918					if (timer - 1 == 0)
1919						next_irq_pending[irq_timer] = 1;
1920			end
1921

